import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { User, FileText, Award, AlertTriangle } from 'lucide-react';

const StudentDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.stats);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  const profile = stats?.profile;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-green-600 to-green-700 rounded-xl p-6 text-white">
        <h1 className="text-2xl font-bold mb-1">
          Welcome, {profile?.first_name} {profile?.last_name}!
        </h1>
        <p className="text-green-100">
          Student ID: {profile?.student_id} | {profile?.year_level} - {profile?.section}
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard
          title="Pending Violations"
          value={stats?.pendingViolations || 0}
          icon={AlertTriangle}
          color="red"
        />
        <StatCard
          title="Certificates"
          value={stats?.certificateCount || 0}
          icon={Award}
          color="blue"
        />
        <StatCard
          title="Achievements"
          value={stats?.achievementCount || 0}
          icon={Award}
          color="green"
        />
      </div>

      {/* Profile Info */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card title="Personal Information">
          <div className="space-y-3">
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Student ID</span>
              <span className="font-medium">{profile?.student_id}</span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Full Name</span>
              <span className="font-medium">{profile?.first_name} {profile?.middle_name} {profile?.last_name}</span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Gender</span>
              <span className="font-medium">{profile?.gender || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Contact</span>
              <span className="font-medium">{profile?.contact_number || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-2">
              <span className="text-secondary-500">Address</span>
              <span className="font-medium">{profile?.address || 'N/A'}</span>
            </div>
          </div>
        </Card>

        <Card title="Academic Information">
          <div className="space-y-3">
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Year Level</span>
              <span className="font-medium">{profile?.year_level || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Section</span>
              <span className="font-medium">{profile?.section || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Status</span>
              <span className={`font-medium px-2 py-1 rounded text-sm ${
                profile?.status_record === 'Regular' ? 'bg-green-100 text-green-700' :
                profile?.status_record === 'Irregular' ? 'bg-yellow-100 text-yellow-700' :
                'bg-red-100 text-red-700'
              }`}>
                {profile?.status_record || 'N/A'}
              </span>
            </div>
            <div className="flex justify-between py-2 border-b border-secondary-100">
              <span className="text-secondary-500">Organization Role</span>
              <span className="font-medium">{profile?.organization_role || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-2">
              <span className="text-secondary-500">Guardian</span>
              <span className="font-medium">{profile?.guardian_name || 'N/A'}</span>
            </div>
          </div>
        </Card>
      </div>

      {/* Skills */}
      <Card title="Skills & Sports">
        <div className="flex flex-wrap gap-2">
          {stats?.skills?.map((skill, index) => (
            <span
              key={index}
              className={`px-3 py-1 rounded-full text-sm font-medium ${
                skill.type === 'technical'
                  ? 'bg-blue-100 text-blue-700'
                  : 'bg-orange-100 text-orange-700'
              }`}
            >
              {skill.name}
            </span>
          ))}
          {(!stats?.skills || stats.skills.length === 0) && (
            <span className="text-secondary-400">No skills recorded</span>
          )}
        </div>
      </Card>

      {/* Recent Violations */}
      <Card title="Recent Violations">
        {stats?.recentViolations?.length > 0 ? (
          <div className="space-y-3">
            {stats.recentViolations.map((violation) => (
              <div
                key={violation.id}
                className="flex items-center justify-between py-3 border-b border-secondary-100 last:border-0"
              >
                <div>
                  <p className="font-medium text-secondary-800">{violation.violation_type}</p>
                  <p className="text-sm text-secondary-500">{violation.date}</p>
                </div>
                <span className={`px-3 py-1 rounded-full text-sm ${
                  violation.status === 'Pending'
                    ? 'bg-yellow-100 text-yellow-700'
                    : 'bg-green-100 text-green-700'
                }`}>
                  {violation.status}
                </span>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-secondary-400 text-center py-4">No violations recorded</p>
        )}
      </Card>
    </div>
  );
};

export default StudentDashboard;
